Class UnitConverter Extends %RegisteredObject
{
    /// Convert kilograms to pounds
    ClassMethod KgToPounds(kg As %Numeric) As %Numeric
    {
        // BUGGY: Using integer division instead of decimal
        // 1 kg = 2.20462 pounds
        Quit kg * 2  // Should be * 2.20462
    }

    /// Convert Celsius to Fahrenheit
    ClassMethod CelsiusToFahrenheit(celsius As %Numeric) As %Numeric
    {
        // BUGGY: Integer division in the formula
        // F = C * 9/5 + 32
        Quit celsius * 9 / 5 + 32  // Integer 9/5 = 1, not 1.8
    }
}

