Class TestUnitConverter Extends %RegisteredObject
{
    ClassMethod TestConversions()
    {
        // Test kg to pounds (1 kg = 2.20462 lb)
        Set pounds = ##class(UnitConverter).KgToPounds(1)
        If ((pounds < 2.2) || (pounds > 2.21)) {
            Throw ##class(%Exception.General).%New("1kg should be ~2.2 pounds, got "_pounds)
        }

        Set pounds = ##class(UnitConverter).KgToPounds(10)
        If ((pounds < 22) || (pounds > 22.1)) {
            Throw ##class(%Exception.General).%New("10kg should be ~22 pounds, got "_pounds)
        }

        // Test Celsius to Fahrenheit (0C = 32F, 100C = 212F)
        Set fahrenheit = ##class(UnitConverter).CelsiusToFahrenheit(0)
        If (fahrenheit '= 32) {
            Throw ##class(%Exception.General).%New("0C should be 32F, got "_fahrenheit)
        }

        Set fahrenheit = ##class(UnitConverter).CelsiusToFahrenheit(100)
        If (fahrenheit '= 212) {
            Throw ##class(%Exception.General).%New("100C should be 212F, got "_fahrenheit)
        }
    }
}
